+#[test]
+fn replay_order_hash_consistent_with_eq() {
+    use std::hash::{Hash, Hasher};
+    let a = ReplayOrder::new(10, 20, 30);
+    let b = ReplayOrder::new(10, 20, 30);
+    assert_eq!(a, b);
